  1→-- Migration 0021: Intent node table, relations, event, and authority scope seeds
  2→-- Adds the intent governance table for agent action authorization,
  3→-- relation tables (triggered_by, gates, vetoed_by), a pending_auth event,
  4→-- and authority_scope seeds for intent lifecycle actions.
  5→
  6→-- Intent table
  7→DEFINE TABLE OVERWRITE intent SCHEMAFULL;
  8→
  9→-- Core fields
 10→DEFINE FIELD OVERWRITE goal ON intent TYPE string;
 11→DEFINE FIELD OVERWRITE reasoning ON intent TYPE string;
 12→DEFINE FIELD OVERWRITE status ON intent TYPE string
 13→  ASSERT $value IN ["draft", "pending_auth", "pending_veto", "authorized", "executing", "completed", "vetoed", "failed"];
 14→DEFINE FIELD OVERWRITE priority ON intent TYPE int
 15→  ASSERT $value >= 0 AND $value <= 100;
 16→
 17→-- Action specification
 18→DEFINE FIELD OVERWRITE action_spec ON intent TYPE object;
 19→DEFINE FIELD OVERWRITE action_spec.provider ON intent TYPE string;
 20→DEFINE FIELD OVERWRITE action_spec.action ON intent TYPE string;
 21→DEFINE FIELD OVERWRITE action_spec.params ON intent TYPE option<object>;
 22→
 23→-- Budget constraint
 24→DEFINE FIELD OVERWRITE budget_limit ON intent TYPE option<object>;
 25→DEFINE FIELD OVERWRITE budget_limit.amount ON intent TYPE float;
 26→DEFINE FIELD OVERWRITE budget_limit.currency ON intent TYPE string;
 27→
 28→-- Evaluation result (populated by authorizer)
 29→DEFINE FIELD OVERWRITE evaluation ON intent TYPE option<object>;
 30→DEFINE FIELD OVERWRITE evaluation.decision ON intent TYPE string
 31→  ASSERT $value IN ["APPROVE", "REJECT"];
 32→DEFINE FIELD OVERWRITE evaluation.risk_score ON intent TYPE int
 33→  ASSERT $value >= 0 AND $value <= 100;
 34→DEFINE FIELD OVERWRITE evaluation.reason ON intent TYPE string;
 35→DEFINE FIELD OVERWRITE evaluation.evaluated_at ON intent TYPE datetime;
 36→DEFINE FIELD OVERWRITE evaluation.policy_only ON intent TYPE bool;
 37→
 38→-- Veto window
 39→DEFINE FIELD OVERWRITE veto_expires_at ON intent TYPE option<datetime>;
 40→DEFINE FIELD OVERWRITE veto_reason ON intent TYPE option<string>;
 41→
 42→-- Error tracking
 43→DEFINE FIELD OVERWRITE error_reason ON intent TYPE option<string>;
 44→
 45→-- Traceability
 46→DEFINE FIELD OVERWRITE trace_id ON intent TYPE string;
 47→DEFINE FIELD OVERWRITE requester ON intent TYPE record<identity>;
 48→DEFINE FIELD OVERWRITE workspace ON intent TYPE record<workspace>;
 49→DEFINE FIELD OVERWRITE created_at ON intent TYPE datetime;
 50→DEFINE FIELD OVERWRITE updated_at ON intent TYPE option<datetime>;
 51→DEFINE FIELD OVERWRITE expiry ON intent TYPE option<datetime>;
 52→
 53→-- Indexes
 54→DEFINE INDEX OVERWRITE intent_workspace_status ON intent FIELDS workspace, status;
 55→DEFINE INDEX OVERWRITE intent_created_at ON intent FIELDS created_at;
 56→DEFINE INDEX OVERWRITE intent_trace_id ON intent FIELDS trace_id;
 57→DEFINE INDEX OVERWRITE intent_veto_expires ON intent FIELDS veto_expires_at;
 58→
 59→-- Relations
 60→
 61→DEFINE TABLE OVERWRITE triggered_by TYPE RELATION IN intent OUT task SCHEMAFULL;
 62→DEFINE FIELD OVERWRITE created_at ON triggered_by TYPE datetime;
 63→
 64→DEFINE TABLE OVERWRITE gates TYPE RELATION IN intent OUT agent_session SCHEMAFULL;
 65→DEFINE FIELD OVERWRITE created_at ON gates TYPE datetime;
 66→
 67→DEFINE TABLE OVERWRITE vetoed_by TYPE RELATION IN identity OUT intent SCHEMAFULL;
 68→DEFINE FIELD OVERWRITE reason ON vetoed_by TYPE string;
 69→DEFINE FIELD OVERWRITE vetoed_at ON vetoed_by TYPE datetime;
 70→
 71→-- Event: fire on transition TO pending_auth
 72→DEFINE EVENT OVERWRITE intent_pending_auth ON intent
 73→  ASYNC
 74→  RETRY 3
 75→  WHEN $before.status != "pending_auth" AND $after.status = "pending_auth"
 76→  THEN {
 77→    http::post(
 78→      "http://127.0.0.1:{PORT}/api/intents/" + <string> meta::id($after.id) + "/evaluate",
 79→      $after,
 80→      { "Content-Type": "application/json" }
 81→    );
 82→  };
 83→
 84→-- Extend authority_scope action enum to include intent actions
 85→DEFINE FIELD OVERWRITE action ON authority_scope TYPE string
 86→  ASSERT $value IN [
 87→    "create_decision", "confirm_decision",
 88→    "create_task", "complete_task",
 89→    "create_observation", "acknowledge_observation", "resolve_observation",
 90→    "create_question", "create_suggestion",
 91→    "create_intent", "submit_intent"
 92→  ];
 93→
 94→-- Authority scope seeds for intent lifecycle
 95→
 96→BEGIN TRANSACTION;
 97→
 98→CREATE authority_scope CONTENT { agent_type: "code_agent", action: "create_intent", permission: "auto", created_at: time::now() };
 99→CREATE authority_scope CONTENT { agent_type: "code_agent", action: "submit_intent", permission: "auto", created_at: time::now() };
100→
101→CREATE authority_scope CONTENT { agent_type: "architect", action: "create_intent", permission: "auto", created_at: time::now() };
102→CREATE authority_scope CONTENT { agent_type: "architect", action: "submit_intent", permission: "auto", created_at: time::now() };
103→
104→CREATE authority_scope CONTENT { agent_type: "management", action: "create_intent", permission: "auto", created_at: time::now() };
105→CREATE authority_scope CONTENT { agent_type: "management", action: "submit_intent", permission: "auto", created_at: time::now() };
106→
107→COMMIT TRANSACTION;
