 1→-- Migration 0023: Introduce trace table and refactor intent.trace_id to record<trace>
 2→--
 3→-- A trace is a forensic "unit of thought" — the hierarchical call tree behind an intent.
 4→-- Replaces the dumb UUID string with a graph-native record link.
 5→
 6→DEFINE TABLE OVERWRITE trace SCHEMAFULL;
 7→DEFINE FIELD type ON trace TYPE string
 8→  ASSERT $value IN ["tool_call", "message", "subagent_spawn", "intent_submission", "bridge_exchange"];
 9→DEFINE FIELD actor ON trace TYPE record<identity>;
10→DEFINE FIELD workspace ON trace TYPE record<workspace>;
11→DEFINE FIELD session ON trace TYPE option<record<agent_session>>;
12→DEFINE FIELD parent_trace ON trace TYPE option<record<trace>>;
13→DEFINE FIELD tool_name ON trace TYPE option<string>;
14→DEFINE FIELD input ON trace TYPE option<object> FLEXIBLE;
15→DEFINE FIELD output ON trace TYPE option<object> FLEXIBLE;
16→DEFINE FIELD duration_ms ON trace TYPE option<int>;
17→DEFINE FIELD created_at ON trace TYPE datetime;
18→
19→DEFINE INDEX trace_parent ON trace FIELDS parent_trace;
20→DEFINE INDEX trace_session ON trace FIELDS session;
21→DEFINE INDEX trace_workspace ON trace FIELDS workspace;
22→DEFINE INDEX trace_created_at ON trace FIELDS created_at;
23→
24→BEGIN TRANSACTION;
25→
26→-- Refactor intent.trace_id from string to record<trace>
27→DEFINE FIELD OVERWRITE trace_id ON intent TYPE record<trace>;
28→DEFINE INDEX OVERWRITE intent_trace_id ON intent FIELDS trace_id;
29→
30→COMMIT TRANSACTION;
