194→export async function listPendingIntents(
195→  surreal: Surreal,
196→  workspaceId: string,
197→): Promise<IntentRecord[]> {
198→  const workspace = new RecordId("workspace", workspaceId);
199→  const [rows] = await surreal.query<[IntentRecord[]]>(
