  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { PolicyRecord, PolicyRule, PolicySelector } from "./types";
  3→
  4→// --- Parameter Types ---
  5→
  6→type CreatePolicyParams = {
  7→  title: string;
  8→  description?: string;
  9→  selector?: PolicySelector;
 10→  rules: PolicyRule[];
 11→  human_veto_required?: boolean;
 12→  max_ttl?: string;
 13→  createdBy: RecordId<"identity">;
 14→  workspace: RecordId<"workspace">;
 15→};
 16→
 17→// --- Query Functions ---
 18→
 19→export async function loadActivePolicies(
 20→  surreal: Surreal,
 21→  identityId: RecordId<"identity">,
 22→  workspaceId: RecordId<"workspace">,
 23→): Promise<PolicyRecord[]> {
 24→  const identityResult = await surreal.query<
 25→    [Array<{ policies: PolicyRecord[] }>]
 26→  >(
 27→    `SELECT ->governing->policy.* AS policies FROM $identity;`,
 28→    { identity: identityId },
 29→  );
 30→
 31→  const workspaceResult = await surreal.query<
 32→    [Array<{ policies: PolicyRecord[] }>]
 33→  >(
 34→    `SELECT <-protects<-policy.* AS policies FROM $workspace;`,
 35→    { workspace: workspaceId },
 36→  );
 37→
 38→  const identityPolicies = identityResult[0]?.[0]?.policies ?? [];
 39→  const workspacePolicies = workspaceResult[0]?.[0]?.policies ?? [];
 40→
 41→  // Deduplicate by policy ID and filter active only
 42→  const seen = new Set<string>();
 43→  const result: PolicyRecord[] = [];
 44→  for (const policy of [...identityPolicies, ...workspacePolicies]) {
 45→    const id = policy.id.id as string;
 46→    if (!seen.has(id) && policy.status === "active") {
 47→      seen.add(id);
 48→      result.push(policy);
 49→    }
 50→  }
 51→  return result;
 52→}
 53→
 54→export async function createPolicy(
 55→  surreal: Surreal,
 56→  params: CreatePolicyParams,
 57→): Promise<{ policyId: string; policyRecord: RecordId<"policy"> }> {
 58→  const policyId = `policy-${crypto.randomUUID()}`;
 59→  const policyRecord = new RecordId("policy", policyId);
 60→
 61→  const content: Record<string, unknown> = {
 62→    title: params.title,
 63→    version: 1,
 64→    status: "draft",
 65→    selector: params.selector ?? {},
 66→    rules: params.rules,
 67→    human_veto_required: params.human_veto_required ?? false,
 68→    created_by: params.createdBy,
 69→    workspace: params.workspace,
 70→    created_at: new Date(),
 71→  };
 72→
 73→  if (params.description) content.description = params.description;
 74→  if (params.max_ttl) content.max_ttl = params.max_ttl;
 75→
 76→  await surreal.query("CREATE $policy CONTENT $content;", {
 77→    policy: policyRecord,
 78→    content,
 79→  });
 80→
 81→  return { policyId, policyRecord };
 82→}
 83→
 84→export async function activatePolicy(
 85→  surreal: Surreal,
 86→  policyId: string,
 87→  creatorId: RecordId<"identity">,
 88→  workspaceId: RecordId<"workspace">,
 89→): Promise<void> {
 90→  const policyRecord = new RecordId("policy", policyId);
 91→
 92→  await surreal.query(
 93→    `
 94→    BEGIN TRANSACTION;
 95→      UPDATE $policy SET status = 'active', updated_at = time::now();
 96→      RELATE $creator->governing->$policy SET created_at = time::now();
 97→      RELATE $policy->protects->$workspace SET created_at = time::now();
 98→    COMMIT TRANSACTION;
 99→  `,
100→    {
101→      policy: policyRecord,
102→      creator: creatorId,
103→      workspace: workspaceId,
104→    },
105→  );
106→}
