  1→import { RecordId } from "surrealdb";
  2→import { jsonError, jsonResponse } from "../http/response";
  3→import { logError, logInfo } from "../http/observability";
  4→import { updateIntentStatus, listPendingIntents, getIntentById } from "./intent-queries";
  5→import { evaluateIntent, createLlmEvaluator } from "./authorizer";
  6→import { routeByRisk } from "./risk-router";
  7→import { renderConsentDisplay, validateTighterBounds } from "../oauth/consent-renderer";
  8→import type { ServerDependencies } from "../runtime/types";
  9→import type { IntentRecord, RoutingDecision } from "./types";
 10→import type { BrainAction } from "../oauth/types";
 11→
 12→// --- Shared Helpers ---
 13→
 14→function resolveRecordId<T extends string>(
 15→  table: T,
 16→  ref: unknown,
 17→): RecordId<T> {
 18→  const rawId = typeof ref === "object" && ref !== null
 19→    ? ((ref as { id: unknown }).id as string)
 20→    : String(ref);
 21→  return new RecordId(table, rawId);
 22→}
 23→
 24→type TransitionPlan = {
 25→  targetStatus: "authorized" | "pending_veto" | "vetoed";
 26→  updateFields: Record<string, unknown>;
 27→  logEvent: string;
 28→  logMessage: string;
 29→  logContext: Record<string, unknown>;
 30→  responseBody: (evaluation: unknown) => Record<string, unknown>;
 31→};
 32→
 33→function routingToTransition(
 34→  routing: RoutingDecision,
 35→  intentId: string,
 36→  evaluationRecord: Record<string, unknown>,
 37→): TransitionPlan {
 38→  switch (routing.route) {
 39→    case "auto_approve":
 40→      return {
 41→        targetStatus: "authorized",
 42→        updateFields: { evaluation: evaluationRecord },
 43→        logEvent: "intent.authorized",
 44→        logMessage: "Intent auto-approved",
 45→        logContext: { intentId },
 46→        responseBody: (evaluation) => ({ intentId, status: "authorized", evaluation }),
 47→      };
 48→    case "veto_window":
 49→      return {
 50→        targetStatus: "pending_veto",
 51→        updateFields: { evaluation: evaluationRecord, veto_expires_at: routing.expires_at },
 52→        logEvent: "intent.pending_veto",
 53→        logMessage: "Intent requires veto window",
 54→        logContext: { intentId, veto_expires_at: routing.expires_at.toISOString() },
 55→        responseBody: (evaluation) => ({
 56→          intentId, status: "pending_veto", evaluation,
 57→          veto_expires_at: routing.expires_at.toISOString(),
 58→        }),
 59→      };
 60→    case "reject":
 61→      return {
 62→        targetStatus: "vetoed",
 63→        updateFields: { evaluation: evaluationRecord },
 64→        logEvent: "intent.vetoed",
 65→        logMessage: "Intent rejected by evaluation",
 66→        logContext: { intentId, reason: routing.reason },
 67→        responseBody: (evaluation) => ({ intentId, status: "vetoed", evaluation }),
 68→      };
 69→  }
 70→}
 71→
 72→// --- Route Handler Types ---
 73→
 74→type IntentRouteHandlers = {
 75→  handleEvaluate: (intentId: string, request: Request) => Promise<Response>;
 76→  handleVeto: (workspaceId: string, intentId: string, request: Request) => Promise<Response>;
 77→  handleListPending: (workspaceId: string) => Promise<Response>;
 78→  handleConsent: (workspaceId: string, intentId: string) => Promise<Response>;
 79→  handleApprove: (workspaceId: string, intentId: string) => Promise<Response>;
 80→  handleConstrain: (workspaceId: string, intentId: string, request: Request) => Promise<Response>;
 81→};
 82→
 83→// --- Factory ---
 84→
 85→export function createIntentRouteHandlers(deps: ServerDependencies): IntentRouteHandlers {
 86→  const { surreal } = deps;
 87→
 88→  const llmEvaluator = createLlmEvaluator(deps.extractionModel);
 89→
 90→  const handleEvaluate = async (intentId: string, request: Request): Promise<Response> => {
 91→    // Called by SurrealQL EVENT via http::post - receives full intent record as body
 92→    let body: IntentRecord | undefined;
 93→    try {
 94→      body = await request.json() as IntentRecord;
 95→    } catch {
 96→      body = undefined;
 97→    }
 98→
 99→    const bodyIntentId = body && typeof body.id === "object" && body.id !== undefined
100→      ? (body.id.id as string)
101→      : undefined;
102→
103→    if (bodyIntentId && bodyIntentId !== intentId) {
104→      return jsonError("Intent ID mismatch between path and payload", 400);
105→    }
106→
107→    if (!body) {
108→      return jsonError("Invalid JSON body", 400);
109→    }
110→
111→    if (!body.requester) {
112→      return jsonError("Missing requester in intent body", 400);
113→    }
114→
115→    logInfo("intent.evaluate.received", "Evaluate endpoint received intent", {
116→      intentId,
117→      status: body.status,
118→      goal: body.goal,
119→    });
120→
121→    // Idempotency guard: only process intents in pending_auth status
122→    if (body.status !== "pending_auth") {
123→      logInfo("intent.evaluate.skipped", "Intent not in pending_auth status", {
124→        intentId,
125→        currentStatus: body.status,
126→      });
127→      return jsonError(`Intent is in '${body.status}' status, expected 'pending_auth'`, 409);
128→    }
129→
130→    try {
131→      const identityId = resolveRecordId("identity", body.requester);
132→      const workspaceRecord = resolveRecordId("workspace", body.workspace);
133→
134→      // Load requester identity type/role for policy evaluation context
135→      const identityRows = (await surreal.query(
136→        `SELECT type, role FROM $identity;`,
137→        { identity: identityId },
138→      )) as Array<Array<{ type?: string; role?: string }>>;
139→      const identityInfo = identityRows[0]?.[0];
140→
141→      const evaluation = await evaluateIntent({
142→        intent: {
143→          goal: body.goal,
144→          reasoning: body.reasoning,
145→          action_spec: body.action_spec,
146→          budget_limit: body.budget_limit,
147→          priority: body.priority,
148→        },
149→        surreal,
150→        identityId,
151→        workspaceId: workspaceRecord,
152→        requesterType: identityInfo?.type ?? "agent",
153→        requesterRole: identityInfo?.role,
154→        llmEvaluator,
155→      });
156→
157→      const routing = routeByRisk(evaluation, {
158→        humanVetoRequired: evaluation.human_veto_required,
159→      });
160→      const evaluationRecord = {
161→        ...evaluation,
162→        evaluated_at: new Date(),
163→      };
164→
165→      const transition = routingToTransition(routing, intentId, evaluationRecord);
166→      const result = await updateIntentStatus(
167→        surreal, intentId, transition.targetStatus, transition.updateFields,
168→      );
169→
170→      if (!result.ok) {
171→        logError(
172→          "intent.evaluate.update_failed",
173→          `Failed to update intent status to ${transition.targetStatus}`,
174→          new Error(result.error),
175→          { intentId },
176→        );
177→        return jsonError(result.error, 409);
178→      }
179→
180→      logInfo(transition.logEvent, transition.logMessage, transition.logContext);
181→      return jsonResponse(transition.responseBody(evaluation), 200);
182→    } catch (error) {
183→      logError("intent.evaluate.error", "Intent evaluation pipeline failed", error, {
184→        intentId,
185→      });
186→      return jsonError("Internal evaluation error", 500);
187→    }
188→  };
189→
190→  const handleVeto = async (
191→    workspaceId: string,
192→    intentId: string,
193→    request: Request,
194→  ): Promise<Response> => {
195→    let body: { reason: string };
196→    try {
197→      body = await request.json() as { reason: string };
198→    } catch {
199→      return jsonError("Invalid JSON body", 400);
200→    }
201→
202→    if (!body.reason || typeof body.reason !== "string" || body.reason.trim().length === 0) {
203→      return jsonError("reason is required", 400);
204→    }
205→
206→    const result = await updateIntentStatus(surreal, intentId, "vetoed", {
207→      veto_reason: body.reason.trim(),
208→    });
209→
210→    if (!result.ok) {
211→      logError("intent.veto.failed", "Failed to veto intent", new Error(result.error), {
212→        intentId,
213→        workspaceId,
214→      });
215→      return jsonError(result.error, 409);
216→    }
217→
218→    logInfo("intent.vetoed", "Intent vetoed by user", {
219→      intentId,
220→      workspaceId,
221→      reason: body.reason.trim(),
222→    });
223→
224→    return jsonResponse({
225→      intentId,
226→      status: "vetoed",
227→    }, 200);
228→  };
229→
230→  const handleListPending = async (workspaceId: string): Promise<Response> => {
231→    const intents = await listPendingIntents(surreal, workspaceId);
232→
233→    return jsonResponse({
234→      intents: intents.map((intent) => ({
235→        id: intent.id.id as string,
236→        goal: intent.goal,
237→        reasoning: intent.reasoning,
238→        priority: intent.priority,
239→        action_spec: intent.action_spec,
240→        veto_expires_at: intent.veto_expires_at,
241→        created_at: intent.created_at,
242→      })),
243→    }, 200);
244→  };
245→
246→  const handleConsent = async (
247→    _workspaceId: string,
248→    intentId: string,
249→  ): Promise<Response> => {
250→    const intent = await getIntentById(surreal, intentId);
251→    if (!intent) {
252→      return jsonError("Intent not found", 404);
253→    }
254→
255→    // Only pending_veto intents have consent display
256→    if (intent.status !== "pending_veto") {
257→      return jsonError(`Intent is in '${intent.status}' status, expected 'pending_veto'`, 409);
258→    }
259→
260→    const authDetails = intent.authorization_details ?? [];
261→    const firstAction = authDetails[0];
262→
263→    const consentDisplay = firstAction
264→      ? renderConsentDisplay(firstAction)
265→      : { action_display: "Unknown", resource_display: "Unknown" };
266→
267→    return jsonResponse({
268→      ...consentDisplay,
269→      risk_score: intent.evaluation?.risk_score ?? 0,
270→      reasoning: intent.evaluation?.reason ?? "",
271→      expires_at: intent.veto_expires_at
272→        ? (intent.veto_expires_at instanceof Date
273→          ? intent.veto_expires_at.toISOString()
274→          : String(intent.veto_expires_at))
275→        : "",
276→    }, 200);
277→  };
278→
279→  const handleApprove = async (
280→    workspaceId: string,
281→    intentId: string,
282→  ): Promise<Response> => {
283→    const result = await updateIntentStatus(surreal, intentId, "authorized");
284→
285→    if (!result.ok) {
286→      logError("intent.approve.failed", "Failed to approve intent", new Error(result.error), {
287→        intentId,
288→        workspaceId,
289→      });
290→      return jsonError(result.error, 409);
291→    }
292→
293→    logInfo("intent.approved", "Intent approved by human", {
294→      intentId,
295→      workspaceId,
296→    });
297→
298→    return jsonResponse({
299→      intentId,
300→      status: "authorized",
301→    }, 200);
302→  };
303→
304→  const handleConstrain = async (
305→    workspaceId: string,
306→    intentId: string,
307→    request: Request,
308→  ): Promise<Response> => {
309→    let body: { constrained_authorization_details: BrainAction[] };
310→    try {
311→      body = await request.json() as { constrained_authorization_details: BrainAction[] };
312→    } catch {
313→      return jsonError("Invalid JSON body", 400);
314→    }
315→
316→    if (!body.constrained_authorization_details || !Array.isArray(body.constrained_authorization_details)) {
317→      return jsonError("constrained_authorization_details is required", 400);
318→    }
319→
320→    const intent = await getIntentById(surreal, intentId);
321→    if (!intent) {
322→      return jsonError("Intent not found", 404);
323→    }
324→
325→    if (intent.status !== "pending_veto") {
326→      return jsonError(`Intent is in '${intent.status}' status, expected 'pending_veto'`, 409);
327→    }
328→
329→    const originalDetails = intent.authorization_details ?? [];
330→    const proposedDetails = body.constrained_authorization_details;
331→
332→    // Validate each proposed action against its original
333→    for (let i = 0; i < proposedDetails.length; i++) {
334→      const original = originalDetails[i];
335→      const proposed = proposedDetails[i];
336→
337→      if (!original) {
338→        return jsonError(`No original authorization_details at index ${i}`, 400);
339→      }
340→
341→      const boundsCheck = validateTighterBounds(original, proposed);
342→      if (!boundsCheck.valid) {
343→        return jsonError(
344→          `Constraint validation failed: ${boundsCheck.violations.join("; ")}`,
345→          400,
346→        );
347→      }
348→    }
349→
350→    // Update intent with tighter constraints and authorize
351→    const record = await updateIntentStatus(surreal, intentId, "authorized", {});
352→    if (!record.ok) {
353→      return jsonError(record.error, 409);
354→    }
355→
356→    // Update the authorization_details with the constrained version
357→    await surreal.query(
358→      "UPDATE $record SET authorization_details = $details;",
359→      {
360→        record: new RecordId("intent", intentId),
361→        details: proposedDetails,
362→      },
363→    );
364→
365→    logInfo("intent.constrained", "Intent constrained and authorized by human", {
366→      intentId,
367→      workspaceId,
368→    });
369→
370→    return jsonResponse({
371→      intentId,
372→      status: "authorized",
373→    }, 200);
374→  };
375→
376→  return { handleEvaluate, handleVeto, handleListPending, handleConsent, handleApprove, handleConstrain };
377→}
