 28→// ---------------------------------------------------------------------------
 29→
 30→export type IntentSubmissionInput = {
 31→  workspace_id: string;
 32→  identity_id: string;
 33→  authorization_details: BrainAction[];
 34→  dpop_jwk_thumbprint: string;
 35→  goal: string;
 36→  reasoning: string;
 37→  priority?: number;
 38→};
