618→/** End an agent session with summary */
619→export async function endAgentSession(input: {
620→  surreal: Surreal;
621→  workspaceRecord: RecordId<"workspace", string>;
622→  sessionId: string;
623→  summary: string;
624→  decisionsMade?: string[];
625→  questionsAsked?: string[];
626→  tasksProgressed?: Array<{ task_id: string; from_status: string; to_status: string }>;
627→  filesChanged?: Array<{ path: string; change_type: string }>;
628→  observationsLogged?: string[];
629→}): Promise<{ session_id: string; ended: boolean }> {
630→  const now = new Date();
631→  const sessionRecord = new RecordId("agent_session", requireRawId(input.sessionId, "session_id"));
632→  const session = await input.surreal.select<{ workspace: RecordId<"workspace", string>; ended_at?: Date; summary?: string }>(sessionRecord);
633→  if (!session) {
634→    throw new Error(`session not found: ${input.sessionId}`);
635→  }
636→  if ((session.workspace.id as string) !== (input.workspaceRecord.id as string)) {
637→    throw new Error("session is outside the current workspace scope");
638→  }
639→
640→  // Idempotent: if session already ended, return without overwriting
641→  if (session.ended_at) {
642→    return { session_id: toRawId(sessionRecord), ended: true };
643→  }
644→
645→  await input.surreal.update(sessionRecord).merge({
646→    ended_at: now,
647→    summary: input.summary,
648→    ...(input.decisionsMade?.length
649→      ? { decisions_made: input.decisionsMade.map((id) => new RecordId("decision", requireRawId(id, "decisions_made[]"))) }
650→      : {}),
651→    ...(input.questionsAsked?.length
652→      ? { questions_asked: input.questionsAsked.map((id) => new RecordId("question", requireRawId(id, "questions_asked[]"))) }
653→      : {}),
654→    ...(input.tasksProgressed?.length
655→      ? {
656→          tasks_progressed: input.tasksProgressed.map((t) => ({
657→            task_id: new RecordId("task", requireRawId(t.task_id, "tasks_progressed[].task_id")),
658→            from_status: t.from_status,
659→            to_status: t.to_status,
660→          })),
661→        }
662→      : {}),
663→    ...(input.filesChanged?.length ? { files_changed: input.filesChanged } : {}),
664→    ...(input.observationsLogged?.length
665→      ? { observations_logged: input.observationsLogged.map((id) => new RecordId("observation", requireRawId(id, "observations_logged[]"))) }
666→      : {}),
667→  });
668→
669→  // Create session -> entity edges
670→  if (input.decisionsMade?.length) {
671→    for (const decisionId of input.decisionsMade) {
672→      const rawDecisionId = requireRawId(decisionId, "decisions_made[]");
673→      await input.surreal
674→        .relate(sessionRecord, new RecordId("produced", randomUUID()), new RecordId("decision", rawDecisionId), {
675→          added_at: now,
676→        })
677→        .output("after");
678→    }
679→  }
680→
681→  if (input.questionsAsked?.length) {
682→    for (const questionId of input.questionsAsked) {
683→      const rawQuestionId = requireRawId(questionId, "questions_asked[]");
684→      await input.surreal
685→        .relate(sessionRecord, new RecordId("asked", randomUUID()), new RecordId("question", rawQuestionId), {
686→          added_at: now,
687→        })
688→        .output("after");
689→    }
690→  }
691→
692→  if (input.tasksProgressed?.length) {
693→    for (const t of input.tasksProgressed) {
694→      const rawTaskId = requireRawId(t.task_id, "tasks_progressed[].task_id");
695→      await input.surreal
696→        .relate(sessionRecord, new RecordId("progressed", randomUUID()), new RecordId("task", rawTaskId), {
697→          from_status: t.from_status,
698→          to_status: t.to_status,
699→          added_at: now,
700→        })
701→        .output("after");
702→    }
703→  }
704→
705→  return { session_id: toRawId(sessionRecord), ended: true };
706→}
