  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { SubagentTrace, SubagentTraceStep } from "../../shared/contracts";
  3→
  4→// ---------------------------------------------------------------------------
  5→// Row types returned by SurrealDB queries
  6→// ---------------------------------------------------------------------------
  7→
  8→type RootTraceRow = {
  9→  id: RecordId<"trace", string>;
 10→  type: string;
 11→  tool_name?: string;
 12→  input?: Record<string, unknown>;
 13→  output?: Record<string, unknown>;
 14→  duration_ms?: number;
 15→  created_at: Date;
 16→  source_message: Array<RecordId<"message", string>>;
 17→};
 18→
 19→type ChildTraceRow = {
 20→  id: RecordId<"trace", string>;
 21→  type: string;
 22→  parent_trace: RecordId<"trace", string>;
 23→  tool_name?: string;
 24→  input?: Record<string, unknown>;
 25→  output?: Record<string, unknown>;
 26→  duration_ms?: number;
 27→  created_at: Date;
 28→};
 29→
 30→// ---------------------------------------------------------------------------
 31→// Pure reconstruction: trace rows -> SubagentTrace wire format
 32→// ---------------------------------------------------------------------------
 33→
 34→/**
 35→ * Reconstruct SubagentTrace wire format from root and child trace rows.
 36→ * Pure function - no IO, no side effects.
 37→ */
 38→export function reconstructTraces(
 39→  rootRows: unknown[],
 40→  childRows: unknown[],
 41→): Map<string, SubagentTrace[]> {
 42→  const roots = rootRows as RootTraceRow[];
 43→  const children = childRows as ChildTraceRow[];
 44→
 45→  if (roots.length === 0) return new Map();
 46→
 47→  // Group children by parent_trace id
 48→  const childrenByParent = new Map<string, ChildTraceRow[]>();
 49→  for (const child of children) {
 50→    const parentId = child.parent_trace.id as string;
 51→    const existing = childrenByParent.get(parentId);
 52→    if (existing) {
 53→      existing.push(child);
 54→    } else {
 55→      childrenByParent.set(parentId, [child]);
 56→    }
 57→  }
 58→
 59→  // Build traces grouped by message id
 60→  const tracesByMessage = new Map<string, SubagentTrace[]>();
 61→
 62→  for (const root of roots) {
 63→    const messageId = extractMessageId(root.source_message);
 64→    if (!messageId) continue;
 65→
 66→    const rootId = root.id.id as string;
 67→    const rootChildren = childrenByParent.get(rootId) ?? [];
 68→    const steps = rootChildren.map(mapChildToStep);
 69→
 70→    const input = root.input as Record<string, unknown> | undefined;
 71→    const trace: SubagentTrace = {
 72→      agentId: (input?.agentId as string) ?? "unknown",
 73→      intent: (input?.intent as string) ?? "unknown",
 74→      steps,
 75→      totalDurationMs: root.duration_ms ?? 0,
 76→    };
 77→
 78→    const existing = tracesByMessage.get(messageId);
 79→    if (existing) {
 80→      existing.push(trace);
 81→    } else {
 82→      tracesByMessage.set(messageId, [trace]);
 83→    }
 84→  }
 85→
 86→  return tracesByMessage;
 87→}
 88→
 89→function extractMessageId(sourceMessage: Array<{ id: string | unknown }>): string | undefined {
 90→  if (!sourceMessage || sourceMessage.length === 0) return undefined;
 91→  return sourceMessage[0]!.id as string;
 92→}
 93→
 94→function mapChildToStep(child: ChildTraceRow): SubagentTraceStep {
 95→  if (child.type === "message") {
 96→    return {
 97→      type: "text",
 98→      text: (child.input as Record<string, unknown>)?.text as string | undefined,
 99→    };
100→  }
101→
102→  return {
103→    type: "tool_call",
104→    ...(child.tool_name ? { toolName: child.tool_name } : {}),
105→    ...(child.input ? { argsJson: JSON.stringify(child.input) } : {}),
106→    ...(child.output ? { resultJson: JSON.stringify(child.output) } : {}),
107→    ...(child.duration_ms !== undefined ? { durationMs: child.duration_ms } : {}),
108→  };
109→}
110→
111→// ---------------------------------------------------------------------------
112→// Write path: persist SubagentTrace as normalized trace records + spawns edge
113→// ---------------------------------------------------------------------------
114→
115→/**
116→ * Persist a SubagentTrace as a root trace record + child trace records + spawns edge.
117→ * All records are created in a single transaction for atomicity.
118→ */
119→export async function persistSubagentTrace(
120→  surreal: Surreal,
121→  messageRecord: RecordId<"message", string>,
122→  workspaceRecord: RecordId<"workspace", string>,
123→  actorRecord: RecordId<"identity", string>,
124→  trace: SubagentTrace,
125→): Promise<void> {
126→  const rootId = crypto.randomUUID();
127→  const now = new Date();
128→
129→  // Build child trace content records
130→  const childEntries = trace.steps.map((step, i) => ({
131→    id: crypto.randomUUID(),
132→    type: step.type === "text" ? "message" : "tool_call",
133→    tool_name: step.type === "tool_call" ? step.toolName : undefined,
134→    input: step.type === "tool_call"
135→      ? (step.argsJson ? JSON.parse(step.argsJson) : undefined)
136→      : (step.text ? { text: step.text } : undefined),
137→    output: step.type === "tool_call" && step.resultJson
138→      ? JSON.parse(step.resultJson)
139→      : undefined,
140→    duration_ms: step.durationMs,
141→    created_at: new Date(now.getTime() + i + 1),
142→  }));
143→
144→  // Single transaction: root + children + spawns edge
145→  const childCreates = childEntries
146→    .map((c) => {
147→      const fields = [
148→        `type: ${JSON.stringify(c.type)}`,
149→        `actor: $actor`,
150→        `workspace: $workspace`,
151→        `parent_trace: $rootRecord`,
152→        `created_at: <datetime> ${JSON.stringify(c.created_at.toISOString())}`,
153→      ];
154→      if (c.tool_name) fields.push(`tool_name: ${JSON.stringify(c.tool_name)}`);
155→      if (c.input) fields.push(`input: ${JSON.stringify(c.input)}`);
156→      if (c.output) fields.push(`output: ${JSON.stringify(c.output)}`);
157→      if (c.duration_ms !== undefined) fields.push(`duration_ms: ${c.duration_ms}`);
158→      return `CREATE type::thing("trace", ${JSON.stringify(c.id)}) CONTENT { ${fields.join(", ")} };`;
159→    })
160→    .join("\n    ");
161→
162→  await surreal.query(
163→    `
164→    BEGIN TRANSACTION;
165→    LET $rootRecord = type::thing("trace", $rootId);
166→    CREATE $rootRecord CONTENT {
167→      type: "subagent_spawn",
168→      actor: $actor,
169→      workspace: $workspace,
170→      tool_name: "invoke_pm_agent",
171→      input: $rootInput,
172→      duration_ms: $durationMs,
173→      created_at: <datetime> $now
174→    };
175→    ${childCreates}
176→    RELATE $message -> spawns -> $rootRecord;
