195→/**
196→ * Batch-load SubagentTraces for a set of message IDs.
197→ * Uses exactly 2 queries: one for root traces via spawns edges, one for children.
198→ * Returns a Map keyed by message ID (string) to SubagentTrace[].
199→ * Messages with no traces are simply absent from the Map.
200→ */
201→export async function batchLoadTraces(
202→  surreal: Surreal,
203→  messageIds: RecordId<"message", string>[],
204→): Promise<Map<string, SubagentTrace[]>> {
205→  if (messageIds.length === 0) return new Map();
206→
207→  // Query 1: All root traces for the message batch via spawns edges
208→  const [rootRows] = await surreal
209→    .query<[RootTraceRow[]]>(
210→      "SELECT *, <-spawns<-message AS source_message FROM trace WHERE <-spawns<-message CONTAINSANY $message_ids;",
211→      { message_ids: messageIds },
212→    )
213→    .collect<[RootTraceRow[]]>();
214→
215→  if (rootRows.length === 0) return new Map();
216→
217→  // Query 2: All children of those roots
218→  const rootIds = rootRows.map((r) => r.id);
219→  const [childRows] = await surreal
220→    .query<[ChildTraceRow[]]>(
221→      "SELECT * FROM trace WHERE parent_trace INSIDE $root_ids ORDER BY created_at ASC, id ASC;",
222→      { root_ids: rootIds },
223→    )
224→    .collect<[ChildTraceRow[]]>();
225→
226→  return reconstructTraces(rootRows, childRows);
227→}
