 6→DEFINE FUNCTION OVERWRITE fn::entity_edges($entity: record, $lim: int) {
 7→  RETURN SELECT id, `in`, out, kind, confidence
 8→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
 9→         depends_on, owns, observes, suggests_for, subtask_of,
10→         governing, protects, triggered_by, gates
11→    WHERE `in` = $entity OR out = $entity
