15→DEFINE FUNCTION OVERWRITE fn::edges_between($ids: array) {
16→  RETURN SELECT id, `in`, out, kind, confidence
17→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
18→         depends_on, owns, observes, suggests_for, subtask_of,
19→         governing, protects, triggered_by, gates
20→    WHERE `in` IN $ids AND out IN $ids;
21→};
