23→DEFINE FUNCTION OVERWRITE fn::graph_neighbors($ids: array) {
24→  RETURN SELECT `in`, out
25→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
26→         depends_on, owns, observes, suggests_for, subtask_of,
27→         governing, protects, triggered_by, gates
