31→DEFINE FUNCTION OVERWRITE fn::workspace_entity_ids($ws: record<workspace>) {
32→  LET $projects = (SELECT VALUE out FROM has_project WHERE `in` = $ws);
33→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` IN $projects);
34→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
35→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out IN $projects);
36→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
37→  LET $identities = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
38→  LET $provenance = (
39→    SELECT VALUE out FROM extraction_relation
40→    WHERE `in` IN (
